string err=Schema.GetValidationError( "Ppp.clientBaseIp" , m_form.w_clientBaseIp.Text );
m_root.ErrorProvider.SetError( m_form.w_clientBaseIp, err );
i_arg1.Cancel=(err.Length!=0);

