{
	m_form.Label5.Text = "Number Of Sessions";
	CallSetters();
}

if(m_form.DDRadioButton5.Checked == true)
{
	m_form.Label5.Text = "Max Sessions Allowed";
	CallSetters();
}

System.Console.WriteLine("  ------- before vlanRange={0}", vlanRange);
