return;

element.ToControlCSSource:
ATMPlugin plugin = (ATMPlugin)m_object.GetAncestor(typeof(ATMPlugin));
if (plugin == null) return null;
return  plugin.pvcRangeList;

ATMPlugin ap = (ATMPlugin)m_object.GetAncestor(typeof(ATMPlugin));
if (ap != null) {
    return ap.atmRangeList;
}
EthernetPlugin ep = (EthernetPlugin)m_object.GetAncestor(typeof(EthernetPlugin));
if (ep != null) {
    return ep.macRangeList;
}
return null;

//System.Console.WriteLine("TO--->");
ATMPlugin ap = (ATMPlugin)m_object.GetAncestor(typeof(ATMPlugin));
if (ap != null) {
   //System.Console.WriteLine("TO---> {0}", atmRange);
    return atmRange;
}
EthernetPlugin ep = (EthernetPlugin)m_object.GetAncestor(typeof(EthernetPlugin));
if (ep != null) {
   //System.Console.WriteLine("TO---> {0}", macRange);
    return macRange;
}
return null;

element.FromControlCSSource:
//System.Console.WriteLine("FROM--->");

ATMPlugin ap = (ATMPlugin)m_object.GetAncestor(typeof(ATMPlugin));
if (ap != null) {
   //System.Console.WriteLine("FROM---> {0}",value);
    atmRange=(AtmRange)value;
}
EthernetPlugin ep = (EthernetPlugin)m_object.GetAncestor(typeof(EthernetPlugin));
if (ep != null) {
   //System.Console.WriteLine("FROM---> {0}",value);
    macRange=(MacRange)value;
}
return;

